   446→// hasPathFrom returns true if there is a directed path from the specified type/namespace/name to the specified Node
   447→func (r *NodeAuthorizer) hasPathFrom(nodeName string, startingType vertexType, startingNamespace, startingName string) (bool, error) {
   448→	r.graph.lock.RLock()
   449→	defer r.graph.lock.RUnlock()
   450→
   451→	nodeVertex, exists := r.graph.getVertexRLocked(nodeVertexType, "", nodeName)
   452→	if !exists {
   453→		return false, fmt.Errorf("unknown node '%s' cannot get %s %s/%s", nodeName, vertexTypes[startingType], startingNamespace, startingName)
   454→	}
   455→
   456→	startingVertex, exists := r.graph.getVertexRLocked(startingType, startingNamespace, startingName)
   457→	if !exists {
   458→		return false, fmt.Errorf("node '%s' cannot get unknown %s %s/%s", nodeName, vertexTypes[startingType], startingNamespace, startingName)
   459→	}
   460→
   461→	if index, indexExists := r.graph.destinationEdgeIndex[startingVertex.ID()]; indexExists {
   462→		// Fast check to see if we know of a destination edge
   463→		if index.has(nodeVertex.ID()) {
   464→			return true, nil
   465→		}
   466→		// For some types of vertices, the destination edge index is authoritative
   467→		// (as long as it exists), hence we can fail-fast here instead of running
   468→		// a potentially costly DFS below.
   469→		if vertexTypeWithAuthoritativeIndex[startingType] {
   470→			return false, fmt.Errorf("node '%s' cannot get %s %s/%s, no relationship to this object was found in the node authorizer graph", nodeName, vertexTypes[startingType], startingNamespace, startingName)
   471→		}
   472→	}
   473→
   474→	found := false
   475→	traversal := &traverse.VisitingDepthFirst{
   476→		EdgeFilter: func(edge graph.Edge) bool {
   477→			if destinationEdge, ok := edge.(*destinationEdge); ok {
   478→				if destinationEdge.DestinationID() != nodeVertex.ID() {
   479→					// Don't follow edges leading to other nodes
   480→					return false
   481→				}
   482→				// We found an edge leading to the node we want
   483→				found = true
   484→			}
   485→			// Visit this edge
   486→			return true
   487→		},
   488→	}
   489→	traversal.Walk(r.graph.graph, startingVertex, func(n graph.Node) bool {
   490→		if n.ID() == nodeVertex.ID() {
   491→			// We found the node we want
   492→			found = true
   493→		}
   494→		// Stop visiting if we've found the node we want
   495→		return found
   496→	})
   497→	if !found {
   498→		return false, fmt.Errorf("node '%s' cannot get %s %s/%s, no relationship to this object was found in the node authorizer graph", nodeName, vertexTypes[startingType], startingNamespace, startingName)
   499→	}
   500→	return true, nil
   501→}
